const toneClass: Record<string, any> = {
  blue: { bg: 'bg-blue-500/15', text: 'text-blue-400', bar: 'bg-blue-500', ring: 'ring-blue-500/25' },
  green: { bg: 'bg-emerald-500/15', text: 'text-emerald-400', bar: 'bg-emerald-500', ring: 'ring-emerald-500/25' },
  purple: { bg: 'bg-violet-500/15', text: 'text-violet-400', bar: 'bg-violet-500', ring: 'ring-violet-500/25' },
  amber: { bg: 'bg-amber-500/15', text: 'text-amber-400', bar: 'bg-amber-500', ring: 'ring-amber-500/25' },
  red: { bg: 'bg-rose-500/15', text: 'text-rose-400', bar: 'bg-rose-500', ring: 'ring-rose-500/25' },
  cyan: { bg: 'bg-cyan-500/15', text: 'text-cyan-400', bar: 'bg-cyan-500', ring: 'ring-cyan-500/25' },
}

function text(row: Row, keys: string[], fallback = '—') { for (const key of keys) { const v = row?.[key]; if (v !== undefined && v !== null && String(v).trim()) return String(v) } return fallback }
function num(v: any, fallback = 0) { const n = Number(v); return Number.isFinite(n) ? n : fallback }
function pct(part: number, total: number) { return total ? Math.round((part / total) * 100) : 0 }
function dateText(v: any) { if (!v) return '—'; const d = new Date(String(v)); return Number.isNaN(d.getTime()) ? String(v).slice(0, 12) : d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) }
function statusTone(s: any) { const x = String(s || '').toLowerCase(); if (x.includes('risk') || x.includes('critical') || x.includes('reject') || x.includes('degrad') || x.includes('failed') || x.includes('over')) return 'red'; if (x.includes('pending') || x.includes('review') || x.includes('warning') || x.includes('late')) return 'amber'; if (x.includes('progress') || x.includes('active') || x.includes('remote')) return 'blue'; if (x.includes('approve') || x.includes('complete') || x.includes('signed') || x.includes('healthy') || x.includes('live') || x.includes('clocked')) return 'green'; return 'purple' }

function initials(name: string) { return name.split(/\s+/).filter(Boolean).slice(0, 2).map(x => x[0]?.toUpperCase()).join('') || 'HR' }
function Avatar({ name, src, small = false }: { name: string; src?: string; small?: boolean }) {
  return <div className={`${small ? 'h-7 w-7 text-[10px]' : 'h-10 w-10 text-xs'} grid shrink-0 place-items-center overflow-hidden rounded-full bg-gradient-to-br from-amber-200 to-rose-300 font-black text-slate-900 ring-2 ring-slate-200`}>{src ? <img src={src} alt="" className="h-full w-full object-cover" /> : initials(name)}</div>
}

function Badge({ children, tone }: { children: any; tone?: string }) {
  const t = toneClass[tone || statusTone(children)] || toneClass.blue
  return <span className={`inline-flex items-center gap-1 rounded-md px-2.5 py-1 text-[11px] font-black ${t.bg} ${t.text}`}>{children}</span>
}

function MiniLine({ tone = 'blue' }: { tone?: string }) {
  const stroke = { blue: '#2563eb', green: '#22c55e', purple: '#7c3aed', amber: '#f59e0b', red: '#ef4444', cyan: '#06b6d4' }[tone] || '#2563eb'
  return <svg viewBox="0 0 120 30" className="h-8 w-28"><polyline points="0,22 12,21 24,24 36,15 48,18 60,10 72,7 84,18 96,12 108,8 120,10" fill="none" stroke={stroke} strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" /></svg>
}

function MetricCard({ title, value, detail, icon: Icon, tone = 'blue', live = false }: any) {
  const t = toneClass[tone] || toneClass.blue
  return <div className="rounded-xl border border-slate-200 bg-white p-4 shadow-sm">
    <div className="flex items-start justify-between gap-4"><div className={`grid h-10 w-10 place-items-center rounded-full ${t.bg} ${t.text} ring-1 ${t.ring}`}><Icon className="h-5 w-5" /></div>{live ? <span className="rounded bg-green-500/20 px-2 py-0.5 text-[10px] font-black text-green-700">LIVE</span> : <MiniLine tone={tone} />}</div>
    <div className="mt-3 text-[12px] font-bold text-slate-500">{title}</div><div className="mt-1 text-3xl font-black tracking-tight text-slate-950">{value}</div><div className="mt-2 text-[11px] font-black text-slate-500"><span className={tone === 'red' ? 'text-rose-400' : 'text-emerald-400'}>{detail?.startsWith('-') ? '↓' : '↑'} {detail}</span></div>
  </div>
}

function Panel({ title, subtitle, children, className = '', right, light = true }: any) {
  return <section className={`${light ? 'border-slate-200 bg-white text-slate-950 shadow-sm' : 'border-slate-200 bg-white/92 text-slate-950 shadow-[0_18px_70px_rgba(0,0,0,.28)]'} rounded-xl border p-4 ${className}`}>
    <div className="mb-4 flex items-center justify-between gap-3"><div><h2 className={`text-[13px] font-black uppercase tracking-wide ${light ? 'text-slate-900' : 'text-blue-400'}`}>{title}</h2>{subtitle ? <p className={`mt-1 text-xs ${light ? 'text-slate-500' : 'text-slate-500'}`}>{subtitle}</p> : null}</div>{right || <Link href="/hr/documents" className={`text-xs font-black ${light ? 'text-violet-600' : 'text-blue-400'}`}>View All</Link>}</div>
    {children}
  </section>
}

function Tabs({ labels, active = 0, light = true }: { labels: string[]; active?: number; light?: boolean }) {
  return <div className={`mb-4 grid overflow-hidden rounded-lg border ${light ? 'border-slate-200 bg-slate-50' : 'border-slate-200 bg-slate-50'}`} style={{ gridTemplateColumns: `repeat(${labels.length}, minmax(0, 1fr))` }}>{labels.map((l, i) => <button key={l} className={`px-3 py-2 text-xs font-black ${i === active ? light ? 'bg-white text-violet-700 shadow-sm' : 'bg-blue-50 text-blue-700' : light ? 'text-slate-500' : 'text-slate-500'}`}>{l}</button>)}</div>
}

